+function drawSpriteDef(
+  ctx: CanvasRenderingContext2D,
+  sprite: string[],
+  palette: Record<string, string>,
+  x: number, y: number, s: number,
+  flipH = false,
+) {
+  const w = sprite[0]?.length ?? 16;
+  const ps = Math.ceil(s);
+  for (let row = 0; row < sprite.length; row++) {
+    const line = sprite[row];
+    for (let col = 0; col < line.length; col++) {
+      const ch = line[col];
+      if (ch === ' ' || ch === '0') continue;
+      const color = palette[ch];
+      if (!color) continue;
+      const px = flipH ? x + (w - 1 - col) * s : x + col * s;
+      ctx.fillStyle = color;
+      ctx.fillRect(Math.round(px), Math.round(y + row * s), ps, ps);
+    }
+  }
+}
+
+function drawCharacter(
+  ctx: CanvasRenderingContext2D,
+  id: string,
+  sprite: string[],
+  palette: Record<string, string>,
+  x: number,
+  y: number,
+  s: number,
+  flipH = false,
+) {
+  const w = sprite[0]?.length ?? 16;
+  const h = sprite.length;
+  const ps = Math.ceil(s);
+
+  // Draw elliptical drop shadow beneath character
+  const shadowWidth = w * s;
+  const shadowHeight = 3;
+  const shadowX = x;
+  const shadowY = y + h * s - shadowHeight / 2;
+  ctx.save();
+  ctx.fillStyle = 'rgba(26, 26, 46, 0.3)'; // #1a1a2e with 0.3 alpha
+  ctx.beginPath();
+  ctx.ellipse(
+    shadowX + shadowWidth / 2,
+    shadowY,
+    shadowWidth / 2,
+    shadowHeight / 2,
+    0,
+    0,
+    2 * Math.PI,
+  );
+  ctx.fill();
+  ctx.restore();
+
+  // Draw 1px dark outline by drawing silhouette behind character
+  ctx.save();
+  ctx.fillStyle = '#1a1a2e';
+  for (let row = 0; row < sprite.length; row++) {
+    const line = sprite[row];
+    for (let col = 0; col < line.length; col++) {
+      const ch = line[col];
+      if (ch === ' ' || ch === '0') continue;
+      // Draw outline pixels around each pixel (up, down, left, right)
+      const pxBase = flipH ? x + (w - 1 - col) * s : x + col * s;
+      const pyBase = y + row * s;
+      const outlineOffsets = [
+        [-1, 0],
+        [1, 0],
+        [0, -1],
+        [0, 1],
+      ];
+      for (const [dx, dy] of outlineOffsets) {
+        ctx.fillRect(Math.round(pxBase + dx), Math.round(pyBase + dy), ps, ps);
+      }
+    }
+  }
+  ctx.restore();
+
+  // Draw character sprite normally
+  drawSpriteDef(ctx, sprite, palette, x, y, s, flipH);
+}
+
+// Sort characters by y coordinate ascending (lower y behind higher y)
+function drawCharactersSorted(
+  ctx: CanvasRenderingContext2D,
+  chars: { id: string; sprite: string[]; palette: Record<string, string>; x: number; y: number; s: number; flipH?: boolean }[],
+) {
+  chars.sort((a, b) => a.y - b.y);
+  for (const c of chars) {
+    drawCharacter(ctx, c.id, c.sprite, c.palette, c.x, c.y, c.s, c.flipH ?? false);
+  }
+}
